 27→function SketchLoadModal({ onClose }) {
 28→  const { project, dispatch } = useSketch();
 29→  const [savedProjects, setSavedProjects] = useState([]);
 30→  const [loading, setLoading] = useState(true);
 31→  const importInputRef = useRef(null);
 32→  const { setFileHandle } = useSketchProject();
 33→
 34→  useEffect(() => {
 35→    listSketchProjects().then((list) => {
 36→      setSavedProjects(list);
 37→      setLoading(false);
 38→    });
 39→  }, []);
 40→
 41→  const handleOpenFile = async () => {
 42→    try {
 43→      const result = await openSketchProjectFile();
 44→      dispatch({ type: 'SKETCH_LOAD', project: result.project });
 45→      setFileHandle(result.fileHandle || null);
 46→      onClose();
 47→    } catch (err) {
 48→      if (!isFilePickerAbortError(err)) {
 49→        console.error('Failed to open sketch file:', err);
 50→      }
 51→    }
 52→  };
 53→
 54→  const handleImportFile = async (e) => {
 55→    const file = e.target.files?.[0];
 56→    if (!file) return;
 57→    try {
 58→      const result = await importSketchProjectFile(file);
 59→      dispatch({ type: 'SKETCH_LOAD', project: result.project });
 60→      setFileHandle(null);
 61→      onClose();
 62→    } catch (err) {
 63→      console.error('Failed to import sketch file:', err);
 64→    } finally {
 65→      e.target.value = '';
 66→    }
 67→  };
 68→
 69→  const handleLoadDraft = async (id) => {
 70→    try {
 71→      const result = await loadSketchProject(id);
 72→      if (result) {
 73→        dispatch({ type: 'SKETCH_LOAD', project: result.project });
 74→        setFileHandle(null);
 75→        onClose();
 76→      }
 77→    } catch (err) {
 78→      console.error('Failed to load sketch draft:', err);
 79→    }
 80→  };
 81→
 82→  const handleDeleteDraft = async (id, name) => {
 83→    if (!window.confirm(`Delete "${name}"?`)) return;
 84→    await deleteSketchProject(id);
 85→    setSavedProjects((prev) => prev.filter((p) => p.id !== id));
 86→  };
 87→
 88→  return (
 89→    <Modal title="Open Sketch Project" onClose={onClose}>
 90→      <div style={{ display: 'flex', flexDirection: 'column', gap: '16px', minWidth: '360px' }}>
 91→        <div style={{ display: 'flex', gap: '8px' }}>
 92→          <button
 93→            onClick={handleOpenFile}
 94→            style={{
 95→              flex: 1, padding: '10px 16px', borderRadius: '6px', border: '1px solid var(--color-border)',
 96→              background: 'var(--color-panel-bg)', cursor: 'pointer', fontFamily: 'var(--font-ui)', fontSize: '13px',
 97→            }}
 98→          >
 99→            Open Project File...
100→          </button>
101→          <button
102→            onClick={() => importInputRef.current?.click()}
103→            style={{
104→              flex: 1, padding: '10px 16px', borderRadius: '6px', border: '1px solid var(--color-border)',
105→              background: 'var(--color-panel-bg)', cursor: 'pointer', fontFamily: 'var(--font-ui)', fontSize: '13px',
106→            }}
107→          >
108→            Import File...
109→          </button>
110→          <input
111→            ref={importInputRef}
112→            type="file"
113→            accept=".json"
114→            onChange={handleImportFile}
115→            style={{ display: 'none' }}
116→          />
117→        </div>
118→
119→        <div>
120→          <h4 style={{ margin: '0 0 8px', fontSize: '12px', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.05em', color: 'var(--color-text-secondary)' }}>
121→            Browser Drafts
122→          </h4>
123→          {loading ? (
124→            <p style={{ fontSize: '13px', color: 'var(--color-text-secondary)' }}>Loading...</p>
125→          ) : savedProjects.length === 0 ? (
126→            <p style={{ fontSize: '13px', color: 'var(--color-text-secondary)' }}>No saved drafts.</p>
127→          ) : (
128→            <div style={{ display: 'flex', flexDirection: 'column', gap: '4px', maxHeight: '300px', overflowY: 'auto' }}>
129→              {savedProjects.map((entry) => (
130→                <div
131→                  key={entry.id}
132→                  style={{
133→                    display: 'flex', alignItems: 'center', gap: '8px', padding: '8px 10px',
134→                    borderRadius: '6px', border: '1px solid var(--color-border)', background: 'var(--color-panel-bg)',
135→                  }}
136→                >
137→                  <div style={{ flex: 1, minWidth: 0 }}>
138→                    <div style={{ fontSize: '13px', fontWeight: 500, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
139→                      {entry.name || 'Untitled'}
140→                    </div>
141→                    {entry.savedAt && (
142→                      <div style={{ fontSize: '11px', color: 'var(--color-text-secondary)', marginTop: '2px' }}>
143→                        {new Date(entry.savedAt).toLocaleString()}
144→                      </div>
145→                    )}
146→                  </div>
147→                  <button
148→                    onClick={() => handleLoadDraft(entry.id)}
149→                    style={{
150→                      padding: '4px 12px', borderRadius: '4px', border: '1px solid var(--color-border)',
151→                      background: 'var(--color-panel-bg)', cursor: 'pointer', fontSize: '12px',
152→                    }}
153→                  >
154→                    Load
155→                  </button>
156→                  <button
157→                    onClick={() => handleDeleteDraft(entry.id, entry.name)}
158→                    style={{
159→                      padding: '4px 8px', borderRadius: '4px', border: '1px solid var(--color-border)',
160→                      background: 'var(--color-panel-bg)', cursor: 'pointer', fontSize: '12px', color: 'var(--color-text-secondary)',
161→                    }}
162→                  >
163→                    Delete
164→                  </button>
165→                </div>
166→              ))}
167→            </div>
168→          )}
169→        </div>
170→      </div>
171→    </Modal>
172→  );
173→}
