844→function createInitialState(project) {
845→  return {
846→    project,
847→    isDirty: false,
848→    savedSnapshot: snapshotSketch(project),
849→    history: [],
850→    future: [],
851→  };
852→}
853→
854→export function SketchProvider({ children, initialProject }) {
855→  const [state, dispatch] = useReducer(
856→    sketchReducer,
857→    normalizeSketchObjects(initialProject || createSketchProject()),
858→    createInitialState
859→  );
860→
861→  return (
862→    <SketchContext.Provider value={{ state, dispatch }}>
863→      {children}
864→    </SketchContext.Provider>
865→  );
866→}
867→
868→export function useSketch() {
869→  const ctx = useContext(SketchContext);
870→  if (!ctx) throw new Error('useSketch must be used within SketchProvider');
871→  const { state, dispatch } = ctx;
872→
873→  const getPart = useCallback(
874→    (partId) => state.project.parts.find((part) => part.id === partId) || null,
875→    [state.project.parts]
876→  );
877→
878→  const getAssembly = useCallback(
879→    (assemblyId) => state.project.assemblies.find((assembly) => assembly.id === assemblyId) || null,
880→    [state.project.assemblies]
881→  );
882→
883→  const getObject = useCallback(
884→    (objectId) => (state.project.objects || []).find((object) => object.id === objectId) || null,
885→    [state.project.objects]
886→  );
887→
888→  const getPartsForAssembly = useCallback(
889→    (assemblyId) => state.project.parts.filter((part) => part.assemblyId === assemblyId),
890→    [state.project.parts]
891→  );
892→
893→  const getChildParts = useCallback(
894→    (parentId) => state.project.parts.filter((part) => part.parentId === parentId),
895→    [state.project.parts]
896→  );
897→
898→  const getAssembliesForObject = useCallback(
899→    (objectId) => state.project.assemblies.filter((assembly) => assembly.objectId === objectId),
900→    [state.project.assemblies]
901→  );
902→
903→  return {
904→    project: state.project,
905→    isDirty: state.isDirty,
906→    canUndo: state.history.length > 0,
907→    canRedo: state.future.length > 0,
908→    dispatch,
909→    getPart,
910→    getAssembly,
911→    getObject,
912→    getPartsForAssembly,
913→    getChildParts,
914→    getAssembliesForObject,
915→  };
916→}
