function screenToModel(screenX, screenY, viewport, svgRect) {
  const x = (screenX - svgRect.left - viewport.panX) / viewport.zoom;
  const y = (screenY - svgRect.top - viewport.panY) / viewport.zoom;
  return { x, y };
}

function useSketchTool() {
  const { dispatch: sketchDispatch, project } = useSketch();
  const {
    activeTool, viewport, snapEnabled, selectedId, selectedType,
    toolState, activeView, activeAssemblyId, dispatch: editorDispatch,
  } = useSketchEditor();

  const ctx = {
    dispatch: sketchDispatch,
    editorDispatch,
    project,
    activeView,
    activeAssemblyId,
    viewport,
    snapEnabled,
    selectedId,
    selectedType,
  };

  switch (activeTool) {
    case 'panel':
    case 'leg':
    case 'frame':
    case 'cutout':
    case 'hole':
      return createPartPlaceHandler({ ...ctx, partType: activeTool });
    case 'dimension':
      return createDimensionHandler(ctx);
    case 'select':
    default:
      return createSketchSelectHandler(ctx);
  }
}

