 33→function buildSheetZones(paper) {
 34→  const border = {
 35→    x: SHEET_TOKENS.margin,
 36→    y: SHEET_TOKENS.margin,
 37→    width: paper.width - SHEET_TOKENS.margin * 2,
 38→    height: paper.height - SHEET_TOKENS.margin * 2,
 39→  };
 40→
 41→  const liveArea = {
 42→    x: border.x + SHEET_TOKENS.innerInset,
 43→    y: border.y + SHEET_TOKENS.innerInset,
 44→    width: border.width - SHEET_TOKENS.innerInset * 2,
 45→    height: border.height - SHEET_TOKENS.innerInset * 2,
 46→  };
 47→
 48→  const footer = {
 49→    x: liveArea.x,
 50→    y: liveArea.y + liveArea.height - SHEET_TOKENS.footerHeight,
 51→    width: liveArea.width,
 52→    height: SHEET_TOKENS.footerHeight,
 53→  };
 54→
 55→  const contentArea = {
 56→    x: liveArea.x,
 57→    y: liveArea.y,
 58→    width: liveArea.width,
 59→    height: footer.y - liveArea.y - SHEET_TOKENS.contentGap,
 60→  };
 61→
 62→  const titleBlock = {
 63→    x: footer.x + footer.width - Math.min(SHEET_TOKENS.titleBlockWidth, footer.width * 0.46),
 64→    y: footer.y,
 65→    width: Math.min(SHEET_TOKENS.titleBlockWidth, footer.width * 0.46),
 66→    height: footer.height,
 67→  };
 68→
 69→  return {
 70→    border,
 71→    liveArea,
 72→    footer,
 73→    contentArea,
 74→    titleBlock,
 75→  };
