 82→function formatCaptionSecondary(viewport, source, sheet) {
 83→  const scaleLabel = resolveViewportScaleLabel(viewport, source, sheet);
 84→  const reference = resolveViewportReferenceNote(viewport, source);
 85→  return `${reference}  |  SCALE ${scaleLabel}`;
