346→export function buildSheetScene(project, sheet, options = {}) {
347→  if (!sheet) return null;
348→
349→  const resolveSource = options.resolveSource || ((proj, vp) => resolveSheetViewportSource(proj, vp, {
350→    activePhaseId: vp.phaseId,
351→    phaseViewMode: vp.phaseViewMode || 'all',
352→  }));
353→
354→  const paper = getPaperPreset(sheet.paperSize);
355→  const zones = buildSheetZones(paper);
356→  const sourceEntries = (sheet.viewports || []).map((viewport) => ({
357→    viewport,
358→    source: resolveSource(project, viewport),
359→  }));
360→  const allowAutoLayout = sheet.layoutTemplate !== 'manual';
361→  const autoEntries = allowAutoLayout
362→    ? sourceEntries.filter((entry) => !entry.viewport.lockAutoLayout)
363→    : [];
364→  const manualEntries = sourceEntries.filter((entry) => entry.viewport.lockAutoLayout);
365→  const autoRects = layoutAutoViewports(autoEntries, zones.contentArea);
366→
367→  const sceneViewports = sourceEntries.map((entry) => {
368→    const rect = autoRects.get(entry.viewport.id)
369→      || fitViewportToSheet(entry.viewport, sheet);
370→    return buildViewportScene(entry.viewport, entry.source, sheet, rect);
371→  });
372→
373→  const sheetIndex = (project?.sheets || []).findIndex((entry) => entry.id === sheet.id);
374→
375→  return {
376→    paper,
377→    title: getSheetDisplayLabel(sheet, Math.max(0, sheetIndex)),
378→    border: zones.border,
379→    liveArea: zones.liveArea,
380→    contentArea: zones.contentArea,
381→    footer: zones.footer,
382→    titleBlock: buildTitleBlock(project, sheet, zones.titleBlock, Math.max(0, sheetIndex), sceneViewports),
383→    viewports: sceneViewports,
384→    graphics: {
385→      colors: SHEET_COLORS,
386→      drawing: DRAWING_GRAPHICS,
387→    },
388→    manualViewportCount: manualEntries.length,
389→  };
390→}
