392→export function materializeSheetViewportFrames(project, sheet) {
393→  if (!sheet) return sheet;
394→
395→  const scene = buildSheetScene(project, {
396→    ...sheet,
397→    layoutTemplate: 'auto',
398→  });
399→
400→  if (!scene) return sheet;
401→
402→  const frameById = new Map(scene.viewports.map((viewport) => [viewport.id, viewport]));
403→
404→  return {
405→    ...sheet,
406→    layoutTemplate: 'manual',
407→    viewports: (sheet.viewports || []).map((viewport) => {
408→      const frame = frameById.get(viewport.id);
409→      if (!frame) {
410→        return {
411→          ...viewport,
412→          lockAutoLayout: true,
413→        };
414→      }
415→
416→      return {
417→        ...viewport,
418→        x: frame.x,
419→        y: frame.y,
420→        width: frame.width,
421→        height: frame.height,
422→        rotation: frame.rotation || 0,
423→        lockAutoLayout: true,
424→      };
425→    }),
426→  };
427→}
