460→export function getDefaultViewportRect(sheet, source, scale = 100, options = {}) {
461→  const paper = getPaperPreset(sheet.paperSize);
462→  const zones = buildSheetZones(paper);
463→  const bounds = source.bounds || { minX: 0, maxX: 1000, minY: 0, maxY: 1000 };
464→  const sourceWidth = Math.max(1000, bounds.maxX - bounds.minX);
465→  const sourceHeight = Math.max(1000, bounds.maxY - bounds.minY);
466→  const role = options.role || (source.kind === '3d_preview' ? 'supplemental' : 'primary');
467→  const baseScale = sourceFitsFrame(source) ? 1 : Math.max(1, scale);
468→  const width = clamp(
469→    source.kind === '3d_preview'
470→      ? zones.contentArea.width * 0.72
471→      : source.kind === 'roof_schedule'
472→        ? zones.contentArea.width * 0.58
473→      : (sourceWidth / baseScale) + SHEET_TOKENS.viewportPadding * 2,
474→    role === 'primary' ? 120 : 84,
475→    role === 'primary' ? zones.contentArea.width * 0.72 : (source.kind === 'roof_schedule' ? zones.contentArea.width * 0.58 : zones.contentArea.width * 0.44)
476→  );
477→  const height = clamp(
478→    source.kind === '3d_preview'
479→      ? zones.contentArea.height * 0.54
480→      : source.kind === 'roof_schedule'
481→        ? zones.contentArea.height * 0.48
482→      : (sourceHeight / baseScale) + SHEET_TOKENS.viewportPadding * 2,
483→    role === 'primary' ? 96 : 72,
484→    role === 'primary' ? zones.contentArea.height * 0.78 : (source.kind === 'roof_schedule' ? zones.contentArea.height * 0.56 : zones.contentArea.height * 0.42)
485→  );
486→
487→  return snapRectToGrid({
488→    x: zones.contentArea.x + SHEET_TOKENS.viewportGutter,
489→    y: zones.contentArea.y + SHEET_TOKENS.viewportGutter,
490→    width,
491→    height,
492→  });
493→}
