 93→    <rect
 94→      x={x}
 95→      y={tag.position.y - height / 2}
 96→      width={width}
 97→      height={height}
 98→      fill={SHEET_COLORS.mask}
 99→      opacity={opacity}
100→      transform={`rotate(${tag.angle || 0}, ${tag.position.x}, ${tag.position.y})`}
101→    />
102→  );
103→}
104→
105→function resolveTagStyle(tag, isRoom) {
106→  const isInformationalMeasurement = (
107→    tag.semanticRole === ANNOTATION_SEMANTIC_ROLES.MEASUREMENT
108→    && tag.trustLevel !== ANNOTATION_TRUST_LEVELS.AUTHORITATIVE
109→  );
110→
111→  if (isRoom) {
112→    return {
113→      textFill: DRAWING_GRAPHICS.annotation.text,
114→      fontWeight: 600,
115→      maskOpacity: 0.92,
116→      leaderStroke: DRAWING_GRAPHICS.annotation.dimensionExtension,
117→      leaderDash: undefined,
118→    };
119→  }
120→
121→  if (isInformationalMeasurement) {
122→    return {
123→      textFill: SHEET_COLORS.textMuted,
124→      fontWeight: 500,
125→      maskOpacity: 0.84,
126→      leaderStroke: SHEET_COLORS.borderMuted,
127→      leaderDash: '6 4',
128→    };
129→  }
130→
131→  return {
132→    textFill: DRAWING_GRAPHICS.annotation.textMuted,
133→    fontWeight: 500,
134→    maskOpacity: 0.92,
135→    leaderStroke: DRAWING_GRAPHICS.annotation.dimensionExtension,
136→    leaderDash: undefined,
137→  };
138→}
139→
140→function TagFigure({ tag }) {
141→  const isRoom = tag.sourceType === 'room';
142→  const nameSize = isRoom
143→    ? DRAWING_GRAPHICS.annotation.roomNameSize
144→    : (tag.fontSize ?? DRAWING_GRAPHICS.annotation.textSize);
145→  const areaSize = DRAWING_GRAPHICS.annotation.roomAreaSize;
146→  const lineHeight = isRoom ? 168 : (tag.lineHeight ?? 150);
147→  const startY = tag.position.y - ((tag.textLines.length - 1) * lineHeight) / 2;
148→  const style = resolveTagStyle(tag, isRoom);
149→
150→  return (
151→    <g key={tag.id}>
152→      {tag.leaderLine ? (
153→        <>
154→          <line
155→            x1={tag.leaderLine.start.x}
156→            y1={tag.leaderLine.start.y}
157→            x2={tag.leaderLine.end.x}
158→            y2={tag.leaderLine.end.y}
159→            stroke={style.leaderStroke}
160→            strokeWidth={DRAWING_GRAPHICS.annotation.dimensionExtensionWidth}
161→            strokeDasharray={style.leaderDash}
162→            vectorEffect="non-scaling-stroke"
163→          />
164→          <circle
165→            cx={tag.leaderLine.start.x}
166→            cy={tag.leaderLine.start.y}
167→            r={nameSize * 0.18}
168→            fill={style.leaderStroke}
169→          />
170→        </>
171→      ) : null}
172→      {tag.mask ? (
173→        <TagTextMask tag={tag} fontSize={nameSize} lineHeight={lineHeight} opacity={style.maskOpacity} />
174→      ) : null}
175→      <text
176→        x={tag.position.x}
177→        y={startY}
178→        textAnchor={tag.textAnchor}
179→        dominantBaseline="middle"
180→        fill={style.textFill}
181→        fontSize={nameSize}
182→        fontWeight={style.fontWeight}
183→        fontFamily="var(--font-blueprint)"
184→        transform={`rotate(${tag.angle || 0}, ${tag.position.x}, ${tag.position.y})`}
185→        style={{ pointerEvents: 'none' }}
186→      >
187→        {tag.textLines.map((line, index) => (
188→          <tspan
189→            key={`${tag.id}-line-${index}`}
190→            x={tag.position.x}
191→            dy={index === 0 ? 0 : lineHeight}
192→            fontSize={isRoom && index > 0 ? areaSize : nameSize}
193→            fill={isRoom && index > 0 ? DRAWING_GRAPHICS.annotation.textMuted : undefined}
194→            fontWeight={isRoom && index > 0 ? 500 : undefined}
195→          >
196→            {line}
197→          </tspan>
198→        ))}
199→      </text>
200→    </g>
201→  );
202→}
203→
204→export default function BlueprintAnnotationLayer({ dimensions = [], tags = [], className = 'annotations' }) {
205→  return (
206→    <g className={className}>
207→      {dimensions.map((figure) => (
208→        <DimensionFigure key={figure.id} figure={figure} />
209→      ))}
210→      {tags.map((tag) => (
211→        <TagFigure key={tag.id} tag={tag} />
212→      ))}
213→    </g>
214→  );
215→}
