338→function addBox(group, materialKey, sx, sy, sz, px, py, pz, materialPalette, isSelected) {
339→  const geo = new THREE.BoxGeometry(Math.max(sx, 1), Math.max(sy, 1), Math.max(sz, 1));
340→  const mesh = new THREE.Mesh(geo, createMeshMaterial(materialPalette, materialKey, isSelected));
341→  mesh.position.set(px, py, pz);
342→  mesh.castShadow = true;
343→  mesh.receiveShadow = true;
344→  addOutline(mesh, materialPalette, isSelected);
345→  group.add(mesh);
