348→function addCylinder(group, materialKey, rTop, rBot, h, segs, px, py, pz, materialPalette, isSelected) {
349→  const geo = new THREE.CylinderGeometry(Math.max(rTop, 0.5), Math.max(rBot, 0.5), Math.max(h, 0.5), segs);
350→  const mesh = new THREE.Mesh(geo, createMeshMaterial(materialPalette, materialKey, isSelected));
