 1→import { generateId } from './ids';
 2→
 3→export const PHASE_COLORS = [
 4→  '#4A90D9', '#E07B39', '#5BAE5B', '#C75D8E',
 5→  '#8B6EC1', '#D4A843', '#44B4B4', '#D05555',
 6→];
 7→
 8→function getPhaseColor(entry, index) {
 9→  if (entry?.color) return entry.color;
10→  const colorIndex = entry?.colorIndex ?? index;
11→  return PHASE_COLORS[colorIndex % PHASE_COLORS.length];
12→}
13→
14→export function createPhase(name, order, color = PHASE_COLORS[0]) {
15→  return {
16→    id: generateId('phase'),
17→    name,
18→    order,
19→    color,
20→    visible: true,
21→  };
22→}
23→
24→export function sortPhases(phases) {
25→  return [...phases].sort((a, b) => a.order - b.order);
26→}
27→
28→export function getOrderedPhases(project) {
29→  return sortPhases(project.phases || []);
30→}
31→
32→export function getNextPhaseOrder(phases) {
33→  if (!phases || phases.length === 0) return 0;
34→  return Math.max(...phases.map(p => p.order)) + 1;
35→}
36→
37→export function reorderPhases(phases, movedId, newOrder) {
38→  const sorted = sortPhases(phases);
39→  const moved = sorted.find(p => p.id === movedId);
40→  if (!moved) return sorted;
41→
42→  const others = sorted.filter(p => p.id !== movedId);
43→  const clamped = Math.max(0, Math.min(newOrder, others.length));
44→  others.splice(clamped, 0, moved);
45→
46→  return others.map((p, i) => ({ ...p, order: i }));
47→}
48→
49→export function normalizePhases(phases = []) {
50→  const normalized = (Array.isArray(phases) ? phases : []).map((phase, index) => ({
51→    id: phase?.id || generateId('phase'),
52→    name: phase?.name || `Phase ${index + 1}`,
53→    order: typeof phase?.order === 'number' ? phase.order : index,
54→    color: getPhaseColor(phase, index),
55→    visible: phase?.visible !== false,
56→  }));
57→
58→  return sortPhases(normalized).map((phase, index) => ({ ...phase, order: index }));
59→}
