 1→import { getPartExtents } from './viewProjection';
 2→
 3→export function bindDimensionToPart(dimension, part, property) {
 4→  const ext = getPartExtents(part);
 5→  const pos = part.position;
 6→
 7→  let startPoint, endPoint, boundAxis;
 8→
 9→  switch (property) {
10→    case 'width':
11→      startPoint = { x: pos.x, y: pos.y, z: pos.z };
12→      endPoint = { x: pos.x + ext.width, y: pos.y, z: pos.z };
13→      boundAxis = 'x';
14→      break;
15→    case 'depth':
16→      startPoint = { x: pos.x, y: pos.y, z: pos.z };
17→      endPoint = { x: pos.x, y: pos.y + ext.depth, z: pos.z };
18→      boundAxis = 'y';
19→      break;
20→    case 'height':
21→    case 'thickness':
22→      startPoint = { x: pos.x, y: pos.y, z: pos.z };
23→      endPoint = { x: pos.x, y: pos.y, z: pos.z + ext.height };
24→      boundAxis = 'z';
25→      break;
26→    case 'length':
27→      // Frame length maps to width or depth depending on axis
28→      startPoint = { x: pos.x, y: pos.y, z: pos.z };
29→      endPoint = part.axis === 'y'
30→        ? { x: pos.x, y: pos.y + ext.depth, z: pos.z }
31→        : { x: pos.x + ext.width, y: pos.y, z: pos.z };
32→      boundAxis = part.axis === 'y' ? 'y' : 'x';
33→      break;
34→    case 'diameter':
35→      startPoint = { x: pos.x, y: pos.y, z: pos.z };
36→      endPoint = { x: pos.x + ext.width, y: pos.y, z: pos.z };
37→      boundAxis = 'x';
38→      break;
39→    default:
40→      return dimension;
41→  }
42→
43→  return {
44→    ...dimension,
45→    startPoint,
46→    endPoint,
47→    boundPartId: part.id,
48→    boundProperty: property,
49→    boundAxis,
50→  };
51→}
52→
53→export function updateBoundDimensionEndpoints(dimension, part) {
54→  if (!dimension.boundPartId || !dimension.boundProperty) return dimension;
55→  return bindDimensionToPart(dimension, part, dimension.boundProperty);
56→}
