 24→function migrateV14toV15(project) {
 25→  if (!Array.isArray(project.sheets)) {
 26→    project.sheets = [];
 27→  }
 28→  if (project.roofSystem === undefined) {
 29→    project.roofSystem = null;
 30→  }
 31→  if (!Array.isArray(project.trussSystems)) {
 32→    project.trussSystems = [];
 33→  }
 34→  if (project.address === undefined) project.address = '';
 35→  project.documentDefaults = {
 36→    drawnBy: project.documentDefaults?.drawnBy ?? '',
 37→    checkedBy: project.documentDefaults?.checkedBy ?? '',
 38→  };
 39→  project.version = Math.max(CURRENT_PROJECT_VERSION, Number(project.version || 0));
 40→
 41→  if (project.floors.length === 0) {
 42→    project.floors = [createFloor('Ground Floor', 0)];
 43→  }
 44→
 45→  // Backfill missing room fields for old saves
 46→  project.floors.forEach((floor, index) => {
 47→    if (!floor.name) floor.name = index === 0 ? 'Ground Floor' : `Floor ${index}`;
 48→    if (floor.levelIndex === undefined) {
 49→      floor.levelIndex = floor.level ?? index;
 50→    }
 51→    if (floor.floorToFloorHeight === undefined) {
 52→      floor.floorToFloorHeight = WALL_HEIGHT;
 53→    }
 54→    if (floor.elevation === undefined) {
 55→      floor.elevation = floor.level ?? (floor.levelIndex * floor.floorToFloorHeight);
 56→    }
 57→    delete floor.level;
 58→
 59→    if (!floor.rooms) floor.rooms = [];
 60→    for (const room of floor.rooms) {
 61→      if (!room.points) room.points = [];
 62→      if (room.area === undefined) room.area = 0;
 63→    }
 64→  });
 65→
 66→  // Backfill door/window type fields for old saves
 67→  for (const floor of project.floors) {
 68→    if (!floor.doors) floor.doors = [];
 69→    for (const door of floor.doors) {
 70→      if (!door.type) door.type = 'swing';
 71→      if (door.height === undefined) door.height = DOOR_HEIGHT;
 72→      if (door.sillHeight === undefined) door.sillHeight = DOOR_SILL_HEIGHT;
 73→    }
 74→    if (!floor.windows) floor.windows = [];
 75→    for (const win of floor.windows) {
 76→      if (!win.type) win.type = 'standard';
 77→      if (!win.openDirection) win.openDirection = 'left';
 78→      if (win.height === undefined) win.height = WINDOW_HEIGHT;
 79→      if (win.sillHeight === undefined) win.sillHeight = WINDOW_SILL_HEIGHT;
 80→    }
 81→    if (!floor.columns) floor.columns = [];
 82→    if (!floor.fixtures) floor.fixtures = [];
 83→    if (!floor.beams) floor.beams = [];
 84→    if (!floor.stairs) floor.stairs = [];
 85→    if (!floor.landings) floor.landings = [];
 86→    if (!floor.annotations) floor.annotations = [];
 87→    if (!floor.railings) floor.railings = [];
 88→    floor.annotationSettings = createAnnotationSettings(floor.annotationSettings || {});
 89→    // Migrate single slab → slabs array
 90→    if (floor.slab !== undefined) {
 91→      floor.slabs = floor.slab ? [floor.slab] : [];
 92→      delete floor.slab;
 93→    }
 94→    if (!Array.isArray(floor.slabs)) floor.slabs = [];
 95→    // Migrate single sectionCut → sectionCuts array
 96→    if (floor.sectionCut !== undefined) {
 97→      floor.sectionCuts = floor.sectionCut ? [floor.sectionCut] : [];
 98→      delete floor.sectionCut;
 99→    }
100→    if (!Array.isArray(floor.sectionCuts)) floor.sectionCuts = [];
101→    for (const wall of floor.walls) {
102→      if (wall.height === undefined) wall.height = WALL_HEIGHT;
103→      if (wall.startAttachment === undefined) wall.startAttachment = null;
104→      if (wall.endAttachment === undefined) wall.endAttachment = null;
105→    }
106→    for (const column of floor.columns) {
107→      if (column.showLabel === undefined) {
108→        column.showLabel = Boolean(column.name);
109→      }
110→    }
111→    for (const fixture of floor.fixtures) {
112→      if (!fixture.fixtureType) fixture.fixtureType = 'kitchenTop';
113→      if (fixture.x === undefined) fixture.x = 0;
114→      if (fixture.y === undefined) fixture.y = 0;
115→      if (fixture.width === undefined) fixture.width = 600;
116→      if (fixture.depth === undefined) fixture.depth = 400;
117→      if (fixture.rotation === undefined) fixture.rotation = 0;
118→      if (fixture.name === undefined) fixture.name = '';
119→    }
120→    for (const beam of floor.beams) {
121→      if (beam.floorLevel === undefined) beam.floorLevel = getFloorElevation(floor, index);
122→    }
123→    for (const stair of floor.stairs) {
124→      if (!stair.startPoint) stair.startPoint = { x: 0, y: 0 };
125→      if (stair.width === undefined) stair.width = STAIR_WIDTH;
126→      if (stair.numberOfRisers === undefined) stair.numberOfRisers = STAIR_RISERS;
127→      if (stair.riserHeight === undefined) stair.riserHeight = STAIR_RISER_HEIGHT;
128→      if (stair.treadDepth === undefined) stair.treadDepth = STAIR_TREAD_DEPTH;
129→      if (stair.direction === undefined) {
130→        stair.direction = { angle: 0 };
131→      } else if (typeof stair.direction === 'number') {
132→        stair.direction = { angle: stair.direction };
133→      } else if (stair.direction.angle === undefined) {
134→        stair.direction.angle = 0;
135→      }
136→      if (stair.floorRelation === undefined) {
137→        stair.floorRelation = { fromFloorId: floor.id, toFloorId: floor.id };
138→      } else {
139→        if (stair.floorRelation.fromFloorId === undefined) stair.floorRelation.fromFloorId = floor.id;
140→        if (stair.floorRelation.toFloorId === undefined) stair.floorRelation.toFloorId = floor.id;
141→      }
142→      if (stair.startLandingAttachment === undefined) stair.startLandingAttachment = null;
143→      if (stair.endLandingAttachment === undefined) stair.endLandingAttachment = null;
144→      if (stair.roofAccess === undefined) stair.roofAccess = null;
145→    }
146→    for (const landing of floor.landings) {
147→      if (!landing.position) landing.position = { x: 0, y: 0 };
148→      if (landing.width === undefined) landing.width = 1000;
149→      if (landing.depth === undefined) landing.depth = 1000;
150→      if (landing.thickness === undefined) landing.thickness = 200;
151→      if (landing.elevation === undefined) landing.elevation = 0;
152→      if (landing.rotation === undefined) landing.rotation = 0;
153→    }
154→    for (const annotation of floor.annotations) {
155→      if (!annotation.id) {
156→        annotation.id = `anno_${floor.id}_${Math.random().toString(36).slice(2, 8)}`;
157→      }
158→      if (!annotation.type) annotation.type = 'dimension';
159→      if (!annotation.mode) annotation.mode = 'aligned';
160→      if (!annotation.startPoint) annotation.startPoint = { x: 0, y: 0 };
161→      if (!annotation.endPoint) annotation.endPoint = { x: 0, y: 0 };
162→      if (annotation.offset === undefined) annotation.offset = 300;
163→      if (annotation.textOverride === undefined) annotation.textOverride = '';
164→    }
165→    for (const slab of floor.slabs) {
166→      if (!slab.floorId) slab.floorId = floor.id;
167→      if (!slab.boundaryPoints) slab.boundaryPoints = [];
168→      if (slab.thickness === undefined) slab.thickness = SLAB_THICKNESS;
169→      if (slab.elevation === undefined) slab.elevation = SLAB_ELEVATION;
170→      if (slab.name === undefined) slab.name = '';
171→      if (slab.type === undefined) slab.type = '';
172→    }
173→    for (const sc of floor.sectionCuts) {
174→      if (!sc.id) {
175→        sc.id = `section_${floor.id}_${Math.random().toString(36).slice(2, 8)}`;
176→      }
177→      if (!sc.startPoint) sc.startPoint = { x: 0, y: 0 };
178→      if (!sc.endPoint) sc.endPoint = { x: 1000, y: 0 };
179→      if (sc.depth === undefined) sc.depth = 2000;
180→      if (sc.label === undefined) sc.label = 'Section A-A';
181→      if (sc.direction === undefined) sc.direction = 1;
182→    }
183→  }
184→
185→  project.floors = sortFloors(project.floors).map((floor, index) => ({
186→    ...floor,
187→    levelIndex: getFloorLevelIndex(floor, index),
188→    elevation: getFloorElevation(floor, index),
189→    floorToFloorHeight: getFloorToFloorHeight(floor),
190→  }));
191→
192→  project.trussSystems = (project.trussSystems || []).map((trussSystem) => {
193→    const floor = project.floors.find((entry) => entry.id === trussSystem.floorId)
194→      || project.floors.find((entry) => entry.id === getDefaultActiveFloorId(project))
195→      || project.floors[0]
196→      || null;
197→    const floorId = floor?.id || null;
198→
199→    return {
200→      ...createTrussSystem(trussSystem.name || 'Truss System'),
201→      ...trussSystem,
202→      id: trussSystem?.id || `truss_system_${Math.random().toString(36).slice(2, 8)}`,
203→      floorId,
204→      phaseId: typeof trussSystem?.phaseId === 'string' && trussSystem.phaseId ? trussSystem.phaseId : null,
205→      baseElevation: trussSystem?.baseElevation ?? (floor ? getFloorTopElevation(floor) : 0),
206→      planRotationOffsetDegrees: normalizeRotationDegrees(trussSystem?.planRotationOffsetDegrees),
207→      planOffset: normalizePlanOffset(trussSystem?.planOffset),
208→      planLengthScale: normalizePlanLengthScale(trussSystem?.planLengthScale),
209→      purlinSystem: createPurlinSystem(trussSystem?.purlinSystem),
210→      trussInstances: (trussSystem.trussInstances || []).map((trussInstance) => ({
211→        ...createTrussInstance({ floorId }),
212→        ...trussInstance,
213→        id: trussInstance?.id || `truss_instance_${Math.random().toString(36).slice(2, 8)}`,
214→        floorId: trussInstance?.floorId || floorId,
215→        material: normalizeTrussMaterial(trussInstance?.material),
216→        startPoint: trussInstance?.startPoint ? { x: trussInstance.startPoint.x, y: trussInstance.startPoint.y } : { x: -6000, y: 0 },
217→        endPoint: trussInstance?.endPoint ? { x: trussInstance.endPoint.x, y: trussInstance.endPoint.y } : { x: 6000, y: 0 },
218→        bearingOffsets: {
219→          start: Number.isFinite(trussInstance?.bearingOffsets?.start) ? trussInstance.bearingOffsets.start : 0,
220→          end: Number.isFinite(trussInstance?.bearingOffsets?.end) ? trussInstance.bearingOffsets.end : 0,
221→        },
222→        overhangs: {
223→          start: Number.isFinite(trussInstance?.overhangs?.start) ? trussInstance.overhangs.start : 300,
224→          end: Number.isFinite(trussInstance?.overhangs?.end) ? trussInstance.overhangs.end : 300,
225→        },
226→        supportMode: trussInstance?.supportMode === TRUSS_SUPPORT_MODES.BEAM_PAIR
227→          ? TRUSS_SUPPORT_MODES.BEAM_PAIR
228→          : null,
229→        supportBeamIds: {
230→          start: typeof trussInstance?.supportBeamIds?.start === 'string' ? trussInstance.supportBeamIds.start : null,
231→          end: typeof trussInstance?.supportBeamIds?.end === 'string' ? trussInstance.supportBeamIds.end : null,
232→        },
233→        supportOffsetAlongAxis: Number.isFinite(trussInstance?.supportOffsetAlongAxis)
234→          ? Math.max(0, trussInstance.supportOffsetAlongAxis)
235→          : 0,
236→        roofAttachmentId: trussInstance?.roofAttachmentId || null,
237→      })),
238→    };
239→  });
240→  project = syncProjectTrussSystems(project);
241→
242→  if (project.roofSystem) {
243→    const roofSystem = {
244→      ...createRoofSystem(project.roofSystem.name || 'Roof'),
245→      ...project.roofSystem,
246→      trussAttachmentId: project.roofSystem.trussAttachmentId || null,
247→      pitchSource: project.roofSystem.pitchSource || (project.roofSystem.trussAttachmentId ? 'truss' : 'manual'),
248→      boundaryPolygon: (project.roofSystem.boundaryPolygon || []).map((point) => ({
249→        x: point.x,
250→        y: point.y,
251→      })),
252→      parapets: (project.roofSystem.parapets || []).map((parapet) => ({
