254→        startPoint: parapet.startPoint ? { x: parapet.startPoint.x, y: parapet.startPoint.y } : { x: 0, y: 0 },
255→        endPoint: parapet.endPoint ? { x: parapet.endPoint.x, y: parapet.endPoint.y } : { x: 1000, y: 0 },
256→        attachment: parapet.attachment
257→          ? {
