259→              edgeIndex: Number.isFinite(parapet.attachment.edgeIndex) ? parapet.attachment.edgeIndex : 0,
260→              startOffset: Number.isFinite(parapet.attachment.startOffset) ? parapet.attachment.startOffset : 0,
261→              endOffset: Number.isFinite(parapet.attachment.endOffset) ? parapet.attachment.endOffset : 0,
262→            }
263→          : null,
