import { materializeTemplateDefinition } from './templateHelpers';

const tableTemplate = {
  type: 'table',
  label: 'Table',
  description: 'Tabletop with four legs at corners',
  parameters: [
    { key: 'width', label: 'Width', type: 'number', default: 1200, min: 200, max: 5000, step: 10, suffix: 'mm' },
    { key: 'depth', label: 'Depth', type: 'number', default: 600, min: 200, max: 3000, step: 10, suffix: 'mm' },
    { key: 'height', label: 'Height', type: 'number', default: 750, min: 200, max: 2000, step: 10, suffix: 'mm' },
    { key: 'topThickness', label: 'Top Thickness', type: 'number', default: 18, min: 6, max: 80, step: 1, suffix: 'mm' },
    { key: 'legWidth', label: 'Leg Width', type: 'number', default: 40, min: 10, max: 200, step: 5, suffix: 'mm' },
    { key: 'legDepth', label: 'Leg Depth', type: 'number', default: 40, min: 10, max: 200, step: 5, suffix: 'mm' },
    { key: 'legInset', label: 'Leg Inset', type: 'number', default: 30, min: 0, max: 200, step: 5, suffix: 'mm' },
  ],
  buildDefinition(params) {
    const { width, depth, height, topThickness, legWidth, legDepth, legInset } = params;
    const legHeight = height - topThickness;

    return {
      name: `Table ${width}×${depth}`,
      summary: 'Parametric table assembly',
      description: 'Tabletop and leg assemblies driven by overall dimensions and inset spacing.',
      dimensions: { width, depth, height },
      assemblies: [
        {
          key: 'top',
          name: 'Top',
          sortIndex: 0,
          parts: [
            {
              type: 'panel',
              role: 'tabletop',
              name: 'Tabletop',
              props: {
                width,
                depth,
                thickness: topThickness,
                material: 'plywood',
                position: { x: 0, y: 0, z: legHeight },
              },
            },
          ],
        },
        {
          key: 'legs',
          name: 'Legs',
          sortIndex: 1,
          parts: [
            {
              type: 'leg',
              role: 'front_left_leg',
              name: 'Front Left Leg',
              props: {
                width: legWidth,
                depth: legDepth,
                height: legHeight,
                position: { x: legInset, y: legInset, z: 0 },
              },
            },
            {
              type: 'leg',
              role: 'front_right_leg',
              name: 'Front Right Leg',
              props: {
                width: legWidth,
                depth: legDepth,
                height: legHeight,
                position: { x: width - legInset - legWidth, y: legInset, z: 0 },
              },
            },
            {
              type: 'leg',
              role: 'rear_left_leg',
              name: 'Rear Left Leg',
              props: {
                width: legWidth,
                depth: legDepth,
                height: legHeight,
                position: { x: legInset, y: depth - legInset - legDepth, z: 0 },
              },
            },
            {
              type: 'leg',
              role: 'rear_right_leg',
              name: 'Rear Right Leg',
              props: {
                width: legWidth,
                depth: legDepth,
                height: legHeight,
                position: { x: width - legInset - legWidth, y: depth - legInset - legDepth, z: 0 },
              },
            },
          ],
        },
      ],
    };
  },
  generate(params) {
    return materializeTemplateDefinition(this.buildDefinition(params));
  },
};

export default tableTemplate;

import { materializeTemplateDefinition } from './templateHelpers';

const cabinetTemplate = {
  type: 'cabinet',
  label: 'Cabinet',
  description: 'Box with sides, shelves, optional doors and back',
  parameters: [
    { key: 'width', label: 'Width', type: 'number', default: 600, min: 200, max: 3000, step: 10, suffix: 'mm' },
    { key: 'depth', label: 'Depth', type: 'number', default: 400, min: 150, max: 1500, step: 10, suffix: 'mm' },
    { key: 'height', label: 'Height', type: 'number', default: 800, min: 200, max: 3000, step: 10, suffix: 'mm' },
    { key: 'panelThickness', label: 'Panel Thickness', type: 'number', default: 18, min: 6, max: 50, step: 1, suffix: 'mm' },
    { key: 'shelfCount', label: 'Shelves', type: 'integer', default: 2, min: 0, max: 10, step: 1, suffix: '' },
    { key: 'hasDoors', label: 'Doors', type: 'boolean', default: false },
    { key: 'hasBack', label: 'Back Panel', type: 'boolean', default: true },
  ],
  buildDefinition(params) {
    const { width, depth, height, panelThickness, shelfCount, hasDoors, hasBack } = params;
    const innerWidth = width - 2 * panelThickness;
    const innerHeight = height - 2 * panelThickness;
    const caseParts = [
      {
        type: 'panel',
        role: 'left_side',
        name: 'Left Side',
        props: {
          width: panelThickness,
          depth,
          thickness: innerHeight,
          material: 'plywood',
          position: { x: 0, y: 0, z: panelThickness },
        },
      },
      {
        type: 'panel',
        role: 'right_side',
        name: 'Right Side',
        props: {
          width: panelThickness,
          depth,
          thickness: innerHeight,
          material: 'plywood',
          position: { x: width - panelThickness, y: 0, z: panelThickness },
        },
      },
      {
        type: 'panel',
        role: 'bottom',
        name: 'Bottom',
        props: {
          width: innerWidth,
          depth,
          thickness: panelThickness,
          material: 'plywood',
          position: { x: panelThickness, y: 0, z: 0 },
        },
      },
      {
        type: 'panel',
        role: 'top',
        name: 'Top',
        props: {
          width: innerWidth,
          depth,
          thickness: panelThickness,
          material: 'plywood',
          position: { x: panelThickness, y: 0, z: height - panelThickness },
        },
      },
    ];

    const shelfParts = [];
    if (shelfCount > 0) {
      const spacing = innerHeight / (shelfCount + 1);
      for (let i = 1; i <= shelfCount; i += 1) {
        const z = panelThickness + spacing * i - panelThickness / 2;
        shelfParts.push({
          type: 'panel',
          role: `shelf_${i}`,
          name: `Shelf ${i}`,
          props: {
            width: innerWidth,
            depth,
            thickness: panelThickness,
            material: 'plywood',
            position: { x: panelThickness, y: 0, z },
          },
        });
      }
    }

    const doorParts = [];
    if (hasDoors) {
      const doorWidth = innerWidth / 2;
      doorParts.push({
        type: 'panel',
        role: 'left_door',
        name: 'Left Door',
        props: {
          width: doorWidth,
          depth: panelThickness,
          thickness: innerHeight,
          material: 'plywood',
          position: { x: panelThickness, y: 0, z: panelThickness },
          fill: 'rgba(184, 134, 11, 0.1)',
        },
      });
      doorParts.push({
        type: 'panel',
        role: 'right_door',
        name: 'Right Door',
        props: {
          width: doorWidth,
          depth: panelThickness,
          thickness: innerHeight,
          material: 'plywood',
          position: { x: panelThickness + doorWidth, y: 0, z: panelThickness },
          fill: 'rgba(184, 134, 11, 0.1)',
        },
      });
    }

    const backParts = hasBack ? [
      {
        type: 'panel',
        role: 'back',
        name: 'Back',
        props: {
          width,
          depth: panelThickness,
          thickness: height,
          material: 'plywood',
          position: { x: 0, y: depth - panelThickness, z: 0 },
          fill: 'rgba(120, 120, 120, 0.06)',
        },
      },
    ] : [];

    return {
      name: `Cabinet ${width}×${depth}×${height}`,
      summary: 'Casework cabinet with configurable shelves and enclosure options',
      description: 'Side panels, horizontal case parts, optional shelves, doors, and back panel.',
      dimensions: { width, depth, height },
      assemblies: [
        { key: 'case', name: 'Case', sortIndex: 0, parts: caseParts },
        { key: 'shelves', name: 'Shelves', sortIndex: 1, parts: shelfParts },
        { key: 'front', name: 'Front', sortIndex: 2, parts: doorParts },
        { key: 'back', name: 'Back', sortIndex: 3, parts: backParts },
      ],
    };
  },
  generate(params) {
    return materializeTemplateDefinition(this.buildDefinition(params));
  },
};

export default cabinetTemplate;

