import tableTemplate from './tableTemplate';
import cabinetTemplate from './cabinetTemplate';
import deskTemplate from './deskTemplate';
import shelfTemplate from './shelfTemplate';

const templates = [tableTemplate, cabinetTemplate, deskTemplate, shelfTemplate];
const templateMap = new Map(templates.map((t) => [t.type, t]));

export const templateList = templates;

export function getTemplate(type) {
  return templateMap.get(type) || null;
}

export function getDefaultParams(type) {
  const template = getTemplate(type);
  if (!template) return {};
  const defaults = {};
  for (const param of template.parameters) {
    defaults[param.key] = param.default;
  }
  return defaults;
}

import { materializeTemplateDefinition } from './templateHelpers';

const deskTemplate = {
  type: 'desk',
  label: 'Desk',
  description: 'Desktop with two side panels and optional back',
  parameters: [
    { key: 'width', label: 'Width', type: 'number', default: 1400, min: 400, max: 5000, step: 10, suffix: 'mm' },
    { key: 'depth', label: 'Depth', type: 'number', default: 600, min: 300, max: 2000, step: 10, suffix: 'mm' },
    { key: 'height', label: 'Height', type: 'number', default: 750, min: 400, max: 1200, step: 10, suffix: 'mm' },
    { key: 'topThickness', label: 'Top Thickness', type: 'number', default: 25, min: 10, max: 80, step: 1, suffix: 'mm' },
    { key: 'sideThickness', label: 'Side Thickness', type: 'number', default: 18, min: 6, max: 50, step: 1, suffix: 'mm' },
    { key: 'hasBackPanel', label: 'Back Panel', type: 'boolean', default: false },
  ],
  buildDefinition(params) {
    const { width, depth, height, topThickness, sideThickness, hasBackPanel } = params;
    const sideHeight = height - topThickness;

    return {
      name: `Desk ${width}×${depth}`,
      summary: 'Desk assembly with top, side supports, and optional modesty panel',
      description: 'Top, support panels, and optional back panel driven by desk dimensions.',
      dimensions: { width, depth, height },
      assemblies: [
        {
          key: 'top',
          name: 'Top',
          sortIndex: 0,
          parts: [
            {
              type: 'panel',
              role: 'desktop',
              name: 'Desktop',
              props: {
                width,
                depth,
                thickness: topThickness,
                material: 'plywood',
                position: { x: 0, y: 0, z: sideHeight },
              },
            },
          ],
        },
        {
          key: 'supports',
          name: 'Supports',
          sortIndex: 1,
          parts: [
            {
              type: 'panel',
              role: 'left_support',
              name: 'Left Side',
              props: {
                width: sideThickness,
                depth,
                thickness: sideHeight,
                material: 'plywood',
                position: { x: 0, y: 0, z: 0 },
              },
            },
            {
              type: 'panel',
              role: 'right_support',
              name: 'Right Side',
              props: {
                width: sideThickness,
                depth,
                thickness: sideHeight,
                material: 'plywood',
                position: { x: width - sideThickness, y: 0, z: 0 },
              },
            },
          ],
        },
        {
          key: 'back',
          name: 'Back Panel',
          sortIndex: 2,
          parts: hasBackPanel ? [
            {
              type: 'panel',
              role: 'modesty_panel',
              name: 'Back Panel',
              props: {
                width: width - 2 * sideThickness,
                depth: sideThickness,
                thickness: sideHeight * 0.6,
                material: 'plywood',
                position: { x: sideThickness, y: depth - sideThickness, z: 0 },
                fill: 'rgba(120, 120, 120, 0.06)',
              },
            },
          ] : [],
        },
      ],
    };
  },
  generate(params) {
    return materializeTemplateDefinition(this.buildDefinition(params));
  },
};

export default deskTemplate;

import { materializeTemplateDefinition } from './templateHelpers';

const shelfTemplate = {
  type: 'shelf',
  label: 'Shelf Unit',
  description: 'Tall shelving with adjustable shelf count',
  parameters: [
    { key: 'width', label: 'Width', type: 'number', default: 800, min: 200, max: 3000, step: 10, suffix: 'mm' },
    { key: 'depth', label: 'Depth', type: 'number', default: 300, min: 100, max: 1000, step: 10, suffix: 'mm' },
    { key: 'height', label: 'Height', type: 'number', default: 1800, min: 400, max: 3000, step: 10, suffix: 'mm' },
    { key: 'sideThickness', label: 'Side Thickness', type: 'number', default: 18, min: 6, max: 50, step: 1, suffix: 'mm' },
    { key: 'shelfThickness', label: 'Shelf Thickness', type: 'number', default: 18, min: 6, max: 50, step: 1, suffix: 'mm' },
    { key: 'shelfCount', label: 'Shelves', type: 'integer', default: 4, min: 1, max: 15, step: 1, suffix: '' },
    { key: 'hasBack', label: 'Back Panel', type: 'boolean', default: true },
  ],
  buildDefinition(params) {
    const { width, depth, height, sideThickness, shelfThickness, shelfCount, hasBack } = params;
    const innerWidth = width - 2 * sideThickness;
    const totalShelves = shelfCount + 2;
    const spacing = height / (totalShelves - 1);
    const shelfParts = [];

    for (let i = 0; i < totalShelves; i += 1) {
      const z = spacing * i;
      const isTopOrBottom = i === 0 || i === totalShelves - 1;
      shelfParts.push({
        type: 'panel',
        role: isTopOrBottom ? (i === 0 ? 'bottom' : 'top') : `shelf_${i}`,
        name: isTopOrBottom ? (i === 0 ? 'Bottom' : 'Top') : `Shelf ${i}`,
        props: {
          width: innerWidth,
          depth,
          thickness: shelfThickness,
          material: 'plywood',
          position: { x: sideThickness, y: 0, z },
        },
      });
    }

    return {
      name: `Shelf ${width}×${height}`,
      summary: 'Shelving unit with fixed side panels and evenly spaced shelf panels',
      description: 'Shelf unit driven by overall height, width, depth, thickness, and shelf count.',
      dimensions: { width, depth, height },
      assemblies: [
        {
          key: 'case',
          name: 'Case',
          sortIndex: 0,
          parts: [
            {
              type: 'panel',
              role: 'left_side',
              name: 'Left Side',
              props: {
                width: sideThickness,
                depth,
                thickness: height,
                material: 'plywood',
                position: { x: 0, y: 0, z: 0 },
              },
            },
            {
              type: 'panel',
              role: 'right_side',
              name: 'Right Side',
              props: {
                width: sideThickness,
                depth,
                thickness: height,
                material: 'plywood',
                position: { x: width - sideThickness, y: 0, z: 0 },
              },
            },
          ],
        },
        {
          key: 'shelves',
          name: 'Shelves',
          sortIndex: 1,
          parts: shelfParts,
        },
        {
          key: 'back',
          name: 'Back',
          sortIndex: 2,
          parts: hasBack ? [
            {
              type: 'panel',
              role: 'back',
              name: 'Back',
              props: {
                width,
                depth: Math.max(6, sideThickness / 2),
                thickness: height,
                material: 'plywood',
                position: { x: 0, y: depth - Math.max(6, sideThickness / 2), z: 0 },
                fill: 'rgba(120, 120, 120, 0.06)',
              },
            },
          ] : [],
        },
      ],
    };
  },
  generate(params) {
    return materializeTemplateDefinition(this.buildDefinition(params));
  },
};

export default shelfTemplate;

