427→
428→      const assembly = state.project.assemblies.find((entry) => entry.id === action.assemblyId);
429→      if (!assembly) return state;
430→
431→      const partIdSet = new Set(assembly.partIds);
432→      let nextProject = {
433→        ...state.project,
434→        updatedAt: new Date().toISOString(),
435→        parts: state.project.parts.map((part) => {
436→          if (!partIdSet.has(part.id) || part.type === 'dimension') return part;
437→          const moved = {
438→            ...part,
439→            position: {
440→              x: part.position.x + (action.delta.dx || 0),
441→              y: part.position.y + (action.delta.dy || 0),
442→              z: part.position.z + (action.delta.dz || 0),
443→            },
444→          };
