768→        sheets: (state.project.sheets || []).map((sheet) => (
769→          sheet.id === action.sheetId
770→            ? { ...sheet, viewports: (sheet.viewports || []).filter((viewport) => viewport.id !== action.viewportId) }
771→            : sheet
772→        )),
773→      });
774→
775→    case 'TEMPLATE_GENERATE': {
776→      const generated = generateObjectFromTemplate(action.templateType, action.params, {
777→        objectId: action.objectId,
778→        name: action.name,
779→        origin: action.origin,
780→      });
781→      return applyUpdate(state, {
782→        ...addGeneratedObject(state.project, generated),
