247→function ConstraintsSection({ part, project, dispatch }) {
248→  const [showForm, setShowForm] = useState(false);
249→  const [cType, setCType] = useState('attach_face');
250→  const [targetId, setTargetId] = useState('');
251→  const [srcAnchor, setSrcAnchor] = useState('bottom');
252→  const [tgtAnchor, setTgtAnchor] = useState('top');
253→  const [offset, setOffset] = useState(0);
254→
255→  const constraints = (project.constraints || []).filter(
256→    (c) => c.sourcePartId === part.id || c.targetPartId === part.id
257→  );
258→
259→  const otherParts = project.parts.filter((p) => p.id !== part.id && p.type !== 'dimension');
260→
261→  const handleAddConstraint = () => {
262→    if (!targetId) return;
263→    const constraint = createConstraint({
264→      type: cType,
265→      sourcePartId: part.id,
266→      targetPartId: targetId,
267→      sourceAnchor: srcAnchor,
268→      targetAnchor: tgtAnchor,
269→      offset: parseFloat(offset) || 0,
270→    });
271→    dispatch({ type: 'CONSTRAINT_ADD', constraint });
272→    setShowForm(false);
273→    setTargetId('');
274→  };
275→
276→  return (
277→    <div className={styles.fieldGroup}>
278→      <span className={styles.groupTitle}>Constraints</span>
279→      <div className={styles.constraintSection}>
280→        {constraints.map((c) => {
281→          const targetPart = project.parts.find((p) => p.id === (c.sourcePartId === part.id ? c.targetPartId : c.sourcePartId));
282→          return (
283→            <div key={c.id} className={styles.constraintItem}>
284→              <span>{c.type}: {c.sourceAnchor} → {c.targetAnchor} ({targetPart?.name || '?'})</span>
285→              <button
286→                className={styles.constraintDelete}
287→                onClick={() => dispatch({ type: 'CONSTRAINT_DELETE', constraintId: c.id })}
288→                title="Remove constraint"
289→              >
290→                ×
291→              </button>
292→            </div>
293→          );
294→        })}
295→      </div>
296→
297→      {!showForm ? (
298→        <button className={styles.duplicateBtn} onClick={() => setShowForm(true)}>
299→          Add Constraint
300→        </button>
301→      ) : (
302→        <div className={styles.constraintSection}>
303→          <SelectInput label="Type" value={cType} options={CONSTRAINT_TYPES} onChange={setCType} />
304→          <label className={styles.field}>
305→            <span className={styles.fieldLabel}>Target</span>
306→            <select className={styles.selectInput} value={targetId} onChange={(e) => setTargetId(e.target.value)}>
307→              <option value="">Select...</option>
308→              {otherParts.map((p) => (
309→                <option key={p.id} value={p.id}>{p.name} ({p.type})</option>
310→              ))}
311→            </select>
312→          </label>
313→          <SelectInput label="Source Anchor" value={srcAnchor} options={ANCHOR_OPTIONS} onChange={setSrcAnchor} />
314→          <SelectInput label="Target Anchor" value={tgtAnchor} options={ANCHOR_OPTIONS} onChange={setTgtAnchor} />
315→          <NumberInput label="Offset" value={offset} suffix="mm" onChange={setOffset} />
316→          <div style={{ display: 'flex', gap: '4px' }}>
317→            <button className={styles.duplicateBtn} onClick={handleAddConstraint}>Create</button>
318→            <button className={styles.duplicateBtn} onClick={() => setShowForm(false)}>Cancel</button>
319→          </div>
320→        </div>
321→      )}
322→    </div>
323→  );
324→}
